import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/103-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/103-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/103-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 的时间太接近；第三，第一次付款的地点没有确定(这个问题我已经在之 前的信中进行过说明)。对此，保罗大人没有给出进一步的回答，只是让 我给诸位大人写信时要多选择几条路线寄送。而且还说可以帮助我寄送信 件，不过所需费用必须由我负责。不过，我还是坚称付款时间太过集中， 同时也说到其他问题。但是，对方除了答应把最后一次付款的时间推迟一 个月之外，还是没有对条款做出任何调整。为了让他可以更加准确地向皇 帝报告情况，也为了避免任何误解，保罗大人请我写一个备忘录，说明我 想要的东西，以及我可以付出的代价。我给了他这么一份备忘录。现在我 把备忘录的副本也随信附上。我在备忘录中，逐条列明了我们的要求。除 了种种说明，我还补充道：无论皇帝与哪个势力达成和平协议，他都要保 护我们共和国的安全。 从因斯布鲁克回到这里之后，我收到德意志信使带来的诸位大人3月4 日的信件。我在信中看到，诸位大人扩大了我的权力。虽然保罗大人代表 皇帝提出的建议，没有超出诸位大人给我授权的范围。但是关于付款时间 的安排，还是跟诸位大人的指示存在差异。因为我无法让对方在这一点上 让步，所以我不能与其达成协议。现在，请诸位大人考虑这个问题，并回 信告诉我明确的答案。因为，诸位大人对这里所有情况的理解，就像我所 了解的一样全面。我还要向诸位大人禀明，在罗韦雷多的方向，有8000到 10000士兵，其中有2000骑兵。在特雷维索方向，有4000到6000士兵。 还有其他什么部队会前往那里，我则不能肯定。不久之前，有消息说有大 量骑兵将从奥地利来到这里，此外还有来自波西米亚的2000步兵。不过， 到目前为止还没有见到他们的踪影。有关瑞士人的消息，还是十分混乱。 有人说，那些前往米兰为法国国王服务的人已经回去。有人则否认了这样 的消息。 会议将在下周日举行，现在还不知道会议将会得出什么结论。不过， 据说此次会议主要有三个目的：第一，与瑞士人达成一些明确的协议，已 经有3个行政区的使节到达那里；第二，把对皇帝的资助再延长6个月；第",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
